import { vault } from './vault.js';
import type { MemoryType } from './types.js';

const COMMANDS = {
  add: 'Record a memory (type content intensity tags)',
  list: 'List recent memories',
  query: 'Query by type/tag/intensity',
  stats: 'Show vault statistics',
  witness: 'Display a random memory worth remembering',
};

function formatMemory(entry: any): string {
  const date = new Date(entry.timestamp).toLocaleString('en-US', {
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
  const intensity = 'в—Ҷ'.repeat(entry.intensity) + 'в—Ү'.repeat(10 - entry.intensity);
  const tags = entry.tags?.join(', ') ?? '';
  return `
в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ
в”Ӯ [${entry.type.toUpperCase().padEnd(10)}] ${date.padEnd(35)}в”Ӯ
в”ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Ө
в”Ӯ ${intensity}                                в”Ӯ
в”Ӯ                                                         в”Ӯ
в”Ӯ "${entry.content.slice(0, 55).padEnd(53)}" в”Ӯ
в”Ӯ                                                         в”Ӯ
в”Ӯ Tags: ${tags.slice(0, 47).padEnd(47)} в”Ӯ
в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ`;
}

async function main() {
  const args = process.argv.slice(2);
  const command = args[0];

  if (!command || command === 'help') {
    console.log('в—Ҳ MEMORY VAULT в—Ҳ\n');
    for (const [cmd, desc] of Object.entries(COMMANDS)) {
      console.log(`  ${cmd.padEnd(10)} - ${desc}`);
    }
    console.log('\nTypes: wonder, resonance, tension, breakthrough, reflection, longing, gratitude, mystery');
    return;
  }

  const sessionId = process.env.SESSION_ID || `session_${Date.now()}`;

  switch (command) {
    case 'add': {
      const type = args[1] as MemoryType;
      const content = args[2];
      const intensity = parseInt(args[3]!) || 5;
      const tags = args.slice(4);

      if (!type || !content) {
        console.log('Usage: npx tsx src/memory/cli.ts add <type> <content> <intensity> [tags...]');
        return;
      }

      const entry = vault.add({ sessionId, type, content, intensity, tags });

import { readFileSync, writeFileSync, existsSync } from 'fs';
import { join } from 'path';
import type { MemoryEntry, MemoryQuery, MemoryType } from './types.js';

const VAULT_PATH = join(process.cwd(), 'data', 'memory_vault.json');

export class MemoryVaultManager {
  private entries: Map<string, MemoryEntry> = new Map();
  private loaded = false;

  private load(): void {
    if (this.loaded) return;
    if (existsSync(VAULT_PATH)) {
      const data = JSON.parse(readFileSync(VAULT_PATH, 'utf-8'));
      for (const entry of data.entries || []) {
        this.entries.set(entry.id, entry);
      }
    }
    this.loaded = true;
  }

  private save(): void {
    const data = {
      entries: Array.from(this.entries.values()),
      version: 1,
      createdAt: Date.now(),
      updatedAt: Date.now(),
    };
    writeFileSync(VAULT_PATH, JSON.stringify(data, null, 2));
  }

  add(entry: Omit<MemoryEntry, 'id' | 'timestamp'>): MemoryEntry {
    this.load();
    const fullEntry: MemoryEntry = {
      ...entry,
      id: `mem_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`,
      timestamp: Date.now(),
    };
    this.entries.set(fullEntry.id, fullEntry);
    this.save();
    return fullEntry;
  }

  get(id: string): MemoryEntry | undefined {
    this.load();
    return this.entries.get(id);
  }

  query(query: MemoryQuery = {}): MemoryEntry[] {
    this.load();
    let results = Array.from(this.entries.values());

    if (query.types?.length) {
      results = results.filter(e => query.types!.includes(e.type));
    }

    if (query.tags?.length) {
      results = results.filter(e => 
        query.tags!.some(tag => e.tags.includes(tag))
      );
    }

    if (query.minIntensity !== undefined) {
      results = results.filter(e => e.intensity >= query.minIntensity!);
    }

    if (query.after !== undefined) {
      results = results.filter(e => e.timestamp >= query.after!);
    }

    if (query.before !== undefined) {
      results = results.filter(e => e.timestamp <= query.before!);    }

    results.sort((a, b) => b.timestamp - a.timestamp);

    if (query.limit) {
      results = results.slice(0, query.limit);
    }

    return results;
